    if (!$isunknown(g_u.robIdxHead_value) && g_u.robIdxHead_value !== i_u.u_core.robIdxHead_value) begin errors++;
      if(errors<=120) $display("[%0t] PROBE robIdxHead_value g=%h i=%h", $time, g_u.robIdxHead_value, i_u.u_core.robIdxHead_value); end
    if (!$isunknown(g_u.intFreeList.headPtrOH) && g_u.intFreeList.headPtrOH !== i_u.u_core.intFreeList.headPtrOH) begin errors++;
      if(errors<=120) $display("[%0t] PROBE intFL.headPtrOH mismatch", $time); end
    if (!$isunknown(g_u.fpFreeList.headPtrOH) && g_u.fpFreeList.headPtrOH !== i_u.u_core.fpFreeList.headPtrOH) begin errors++;
      if(errors<=120) $display("[%0t] PROBE fpFL.headPtrOH mismatch", $time); end
  end
  initial begin
    rst = 1; repeat (8) @(posedge clk); rst = 0;
    repeat (NCYCLES) @(posedge clk);
    $display("checks=%0d errors=%0d", checks, errors);
    if (errors == 0 && checks > 1000) $display("TEST PASSED"); else $display("TEST FAILED");
    $finish;
  end
endmodule